// Workers-safe AI helpers for the news pipeline.
//
// IMPORTANT — billing mode. News is a BACKGROUND-AI app: summaries, podcast
// scripts and article images are generated by cron/queue jobs with no end
// user present. The published app runs in ugly.bot auth mode ("Mode A"),
// where the framework's AiText/AiImage clients force the *user-billed*
// endpoint (`/user-billed/text`) and require an end-user session token — which
// background jobs don't have (→ UnauthenticatedAiCallError). So we call the
// *owner-billed* proxy endpoints directly with the app's owner AI token
// (`AI_PROXY_TOKEN`, minted at publish), exactly the shape AiText/AiImage use
// in owner mode. Pure `fetch` — bundles for Node and Workers.
import type { ImageGenModel } from 'ugly-app/shared';
import {
  createEmbeddingClient,
  getAdapter,
} from 'ugly-app/server/adapter/workers';
import { base64ToBytes } from '../../shared/news/WAV';
import type { NewsCategory } from '../../shared/news/types';

export interface ChatMessage {
  role: 'system' | 'user' | 'assistant';
  content: string;
}

// NOTE: must match the live host. `api.ugly.bot` does NOT resolve — verified
// against the proxy; the working host is `ugly.bot/v1/ai` (same default
// server/news/email.ts uses). Prod normally sets AI_PROXY_URL at publish, but a
// correct fallback avoids a silent total-AI-outage if that env is ever missing.
const DEFAULT_AI_PROXY_URL = 'https://ugly.bot/v1/ai';

function aiProxy(): { baseUrl: string; token: string } {
  /* eslint-disable @typescript-eslint/dot-notation */
  const baseUrl = (process.env['AI_PROXY_URL'] ?? DEFAULT_AI_PROXY_URL).replace(
    /\/$/,
    '',
  );
  const token = process.env['AI_PROXY_TOKEN'] ?? '';
  /* eslint-enable @typescript-eslint/dot-notation */
  return { baseUrl, token };
}

// Bursty cron sweeps are the root cause of the `[cluster-*]` "genText returned
// null" / "both summaries non-substantive" errors: the hourly `newsHourly` tick
// fires feed downloads (→ per-article scrape genText+genImage) AND the cluster
// sweep (up to 8 synth × 2 genText + 8 satire × 1 genText, plus images) at the
// same instant. That flood of parallel proxy calls trips ugly.bot's rate
// limiter → HTTP 429 ("Rate limit exceeded"), and we used to give up on the
// first 429. Retry transient failures with exponential backoff + FULL jitter so
// the retries de-correlate and land after the limit window instead of hammering
// it again immediately. 4 attempts / ~≤7s worst case fits the 60s queue-job
// budget (even doubled by genSummary's substantive-retry loop).
const AI_MAX_ATTEMPTS = 4;

/** Transient statuses worth retrying (rate limit / timeout / server blip). A
 *  permanent 4xx (400/401/403) is NOT retried — it would just fail again. */
function isRetryableStatus(status: number): boolean {
  return status === 408 || status === 429 || status >= 500;
}

/** Sleep for exponential backoff with full jitter. `attempt` is 1-based. */
async function backoffDelay(attempt: number): Promise<void> {
  const base = Math.min(500 * 2 ** (attempt - 1), 4000); // 500, 1000, 2000, 4000…
  const delay = base + Math.random() * base; // full jitter → [base, 2·base)
  await new Promise((resolve) => setTimeout(resolve, delay));
}

/**
 * POST JSON to an AI-proxy endpoint, retrying transient 429/5xx responses and
 * network errors with exponential backoff + jitter. Returns the final `Response`
 * (its body untouched, so the caller parses it) — which may still be `!ok` on a
 * permanent 4xx or after exhausting retries — or `null` if every attempt threw
 * before producing a response.
 */
async function postAi(
  baseUrl: string,
  path: string,
  token: string,
  body: unknown,
): Promise<Response | null> {
  let lastRes: Response | null = null;
  for (let attempt = 1; attempt <= AI_MAX_ATTEMPTS; attempt++) {
    try {
      const res = await fetch(`${baseUrl}${path}`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(body),
      });
      if (res.ok || !isRetryableStatus(res.status)) return res;
      lastRes = res;
      console.warn(
        `[news/ai] ${path} ${res.status} (attempt ${attempt}/${AI_MAX_ATTEMPTS})${attempt < AI_MAX_ATTEMPTS ? ' — backing off' : ' — giving up'}`,
      );
    } catch (error) {
      lastRes = null;
      console.warn(
        `[news/ai] ${path} network error (attempt ${attempt}/${AI_MAX_ATTEMPTS})`,
        error,
      );
    }
    if (attempt < AI_MAX_ATTEMPTS) await backoffDelay(attempt);
  }
  return lastRes;
}

interface ContentPart {
  type: string;
  text?: string;
  thinking?: string;
}
/** The proxy returns `message.content` as a string OR an array of parts
 *  (gpt → string; reasoning models → [{type:'thinking'}, {type:'text'}]). */
function extractContent(data: unknown): string {
  const msg = (data as { message?: { content?: unknown }; content?: unknown })
    .message;
  const content = msg?.content ?? (data as { content?: unknown }).content;
  if (typeof content === 'string') return content.trim();
  if (Array.isArray(content)) {
    const text = (content as ContentPart[])
      .filter((p) => p.type === 'text' && typeof p.text === 'string')
      .map((p) => p.text)
      .join('')
      .trim();
    return text;
  }
  return '';
}

/** Owner-billed text generation via the ugly.bot AI proxy. */
export async function genText(
  messages: ChatMessage[],
  opts: { model: string; temperature?: number; maxTokens?: number },
): Promise<string | null> {
  const { baseUrl, token } = aiProxy();
  if (!token) {
    console.warn('[news/ai] genText: AI_PROXY_TOKEN not set');
    return null;
  }
  const res = await postAi(baseUrl, '/text', token, {
    model: opts.model,
    messages,
    userId: 'uglyBot',
    options: {
      ...(opts.temperature !== undefined
        ? { temperature: opts.temperature }
        : {}),
      ...(opts.maxTokens !== undefined ? { maxTokens: opts.maxTokens } : {}),
    },
  });
  if (!res) {
    console.warn('[news/ai] genText: no response after retries');
    return null;
  }
  if (!res.ok) {
    console.warn(
      `[news/ai] genText ${res.status}: ${(await res.text().catch(() => '')).slice(0, 200)}`,
    );
    return null;
  }
  try {
    return extractContent(await res.json()) || null;
  } catch (error) {
    console.warn('[news/ai] genText: failed to parse response', error);
    return null;
  }
}

/** Owner-billed image generation (returns a URL or data URI), or null. */
export async function genImage(
  prompt: string,
  opts?: { model?: ImageGenModel; negative?: string },
): Promise<string | null> {
  const { baseUrl, token } = aiProxy();
  if (!token) {
    console.warn('[news/ai] genImage: AI_PROXY_TOKEN not set');
    return null;
  }
  const fullPrompt = opts?.negative
    ? `${prompt}\n\nAvoid: ${opts.negative}`
    : prompt;
  const res = await postAi(baseUrl, '/image', token, {
    model: opts?.model ?? 'flux_1_dev',
    prompt: fullPrompt,
    userId: 'uglyBot',
    options: { aspectRatio: 'landscape_16_9' },
  });
  if (!res) {
    console.warn('[news/ai] genImage: no response after retries');
    return null;
  }
  if (!res.ok) {
    console.warn(
      `[news/ai] genImage ${res.status}: ${(await res.text().catch(() => '')).slice(0, 200)}`,
    );
    return null;
  }
  try {
    const data = (await res.json()) as {
      url?: string;
      base64?: string;
      mime?: string;
    };
    if (data.url) return data.url;
    if (data.base64)
      return await hostGeneratedImage(data.base64, data.mime ?? 'image/png');
    return null;
  } catch (error) {
    console.warn('[news/ai] genImage: failed to parse response', error);
    return null;
  }
}

/**
 * "The Ugly Press" house illustration for a news subject (article title or
 * cluster headline). Every generated news image shares the paper's editorial
 * newspaper-brutalist look so the feed reads as one publication, not a grab-bag
 * of stock photography. Used at DISPLAY-PROMOTION points only (qualifying story
 * clusters + their Ugly Take) — never eagerly per scraped article — so we spend
 * one generation per shown story instead of one per article.
 */
export async function generateUglyPressImage(
  subject: string,
  category: NewsCategory,
): Promise<string | null> {
  const prompt = [
    `Editorial illustration for a satirical newspaper, "The Ugly Press", depicting: ${subject}.`,
    'Style: bold mid-century editorial newspaper illustration, screen-printed / risograph look, heavy ink linework, visible halftone dot texture, slightly distressed newsprint grain.',
    'Limited palette: warm cream newsprint background, deep ink black, and a single vermilion red accent.',
    `Conceptual and a little wry, fitting the ${category} desk. Strong composition, high contrast, flat shapes.`,
    'Absolutely no text, words, letters, numbers, captions, or logos.',
  ].join(' ');
  const negative =
    'text, words, letters, numbers, captions, watermark, signature, logo, photorealistic, 3d render, glossy, low quality, blurry';
  return genImage(prompt, { model: 'flux_1_dev', negative });
}

// The AI image proxy returns raw base64 for models that don't self-host (e.g.
// flux_1_dev). Persisting that as a `data:` URI bloats every `file` doc by
// ~300KB and breaks the daily email (Gmail clips messages >~102KB, and clients
// strip `data:` images). Re-host it in the app's own public R2 bucket —
// content-addressed by sha256 so identical renders dedupe — and return the
// same-origin URL, exactly like podcast audio / the TTS cache. On any storage
// failure we drop the (decorative) image rather than fall back to a data URI.
async function hostGeneratedImage(
  base64: string,
  mime: string,
): Promise<string | null> {
  try {
    const bytes = base64ToBytes(base64);
    // Copy into a plain ArrayBuffer so digest() accepts it (Uint8Array may be
    // backed by SharedArrayBuffer, which isn't a BufferSource).
    const ab = new ArrayBuffer(bytes.byteLength);
    new Uint8Array(ab).set(bytes);
    const digest = await crypto.subtle.digest('SHA-256', ab);
    const hash = [...new Uint8Array(digest)]
      .map((b) => b.toString(16).padStart(2, '0'))
      .join('');
    const ext = mime.includes('png')
      ? 'png'
      : mime.includes('webp')
        ? 'webp'
        : 'jpg';
    const key = `gen-images/${hash}.${ext}`;
    const storage = getAdapter().storage;
    await storage.put('public', key, bytes, mime);
    return storage.url('public', key);
  } catch (error) {
    console.warn(
      '[news/ai] genImage: R2 upload failed — dropping image',
      error,
    );
    return null;
  }
}

// Semantic embeddings (512-dim, matching the `file` collection's declared
// vector { dimensions: 512 } column) route through ugly.bot's `embedGen` proxy
// — NOT a direct OpenAI call. embedGen runs OpenAI text-embedding-3-small with
// the key held centrally in ugly.bot, and meters/bills the call against the
// app's account (same platform pattern as bahai-app). `createEmbeddingClient`
// from the workers adapter is a thin fetch wrapper over `uglyBotRequest`.
const EMBED_DIMS = 512;
let embeddingClient: ReturnType<typeof createEmbeddingClient> | null = null;

/** ugly.bot embedGen embedding for feed ranking / search (512-dim), or null. */
export async function embed(text: string): Promise<number[] | null> {
  const input = text.trim().slice(0, 8000) || ' ';
  try {
    embeddingClient ??= createEmbeddingClient();
    const vec = await embeddingClient.embed(input, { dimensions: EMBED_DIMS });
    return vec ?? null;
  } catch (error) {
    console.warn('[news/ai] embed failed', error);
    return null;
  }
}

/** ~4 chars/token heuristic truncation (ported from ugly.bot Helper). */
export function truncateToApproximateTokens(
  text: string,
  maxTokens: number,
): string {
  const maxChars = maxTokens * 4;
  return text.length <= maxChars ? text : text.slice(0, maxChars);
}
